+// JSON row accessor helpers
+
+func jsonStr(row map[string]interface{}, key string) string {
+	v, ok := row[key]
+	if !ok || v == nil {
+		return ""
+	}
+	switch val := v.(type) {
+	case string:
+		return val
+	case float64:
+		// JSON numbers come as float64
+		if val == float64(int64(val)) {
+			return strconv.FormatInt(int64(val), 10)
+		}
+		return strconv.FormatFloat(val, 'f', -1, 64)
+	default:
+		return fmt.Sprintf("%v", v)
+	}
+}
+
+func jsonNullableStr(row map[string]interface{}, key string) *string {
+	v, ok := row[key]
+	if !ok || v == nil {
+		return nil
+	}
+	s := fmt.Sprintf("%v", v)
+	return &s
+}
+
+func jsonInt(row map[string]interface{}, key string) int {
+	v, ok := row[key]
+	if !ok || v == nil {
+		return 0
+	}
+	switch val := v.(type) {
+	case float64:
+		return int(val)
+	case string:
+		i, _ := strconv.Atoi(val)
+		return i
+	default:
+		return 0
+	}
+}
+
+func jsonInt64(row map[string]interface{}, key string) int64 {
+	v, ok := row[key]
+	if !ok || v == nil {
+		return 0
+	}
+	switch val := v.(type) {
+	case float64:
+		return int64(val)
+	case string:
+		i, _ := strconv.ParseInt(val, 10, 64)
+		return i
+	default:
+		return 0
+	}
+}
+
+func jsonBool(row map[string]interface{}, key string) bool {
+	v, ok := row[key]
+	if !ok || v == nil {
+		return false
+	}
+	switch val := v.(type) {
+	case bool:
+		return val
+	case float64:
+		return val != 0
+	case string:
+		return val == "1" || val == "true"
+	default:
+		return false
+	}
+}
+
+func jsonNullableInt(row map[string]interface{}, key string) *int {
+	v, ok := row[key]
+	if !ok || v == nil {
+		return nil
+	}
+	switch val := v.(type) {
+	case float64:
+		i := int(val)
+		return &i
+	case string:
+		i, err := strconv.Atoi(val)
+		if err != nil {
+			return nil
+		}
+		return &i
+	default:
+		return nil
+	}
+}
+
+func jsonTime(row map[string]interface{}, key string) time.Time {
+	s := jsonStr(row, key)
+	if s == "" {
+		return time.Time{}
+	}
+	for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02T15:04:05.999999999Z07:00", "2006-01-02 15:04:05"} {
+		if t, err := time.Parse(layout, s); err == nil {
+			return t
+		}
+	}
+	return time.Time{}
+}
+
+func jsonNullableFloat32(row map[string]interface{}, key string) *float32 {
+	v, ok := row[key]
+	if !ok || v == nil {
+		return nil
+	}
+	switch val := v.(type) {
+	case float64:
+		f := float32(val)
+		return &f
+	case string:
+		f, err := strconv.ParseFloat(val, 32)
+		if err != nil {
+			return nil
+		}
+		f32 := float32(f)
+		return &f32
+	default:
+		return nil
+	}
+}

